249	// installLocal installs a plugin from a local directory into the current
250	// checkout as a developer overlay. It intentionally does not update installed
251	// state and does not auto-commit: the recorded plugin pin remains whatever the
252	// project already declares, while this machine can test a local plugin tree.
253	func (f *CommandFactory) installLocal(name, localPath string, force bool, out io.Writer) error {
254		// Resolve to absolute path.
255		absPath, err := filepath.Abs(localPath)
256		if err != nil {
257			return fmt.Errorf("resolving path %s: %w", localPath, err)
258		}
259		if _, err := os.Stat(absPath); os.IsNotExist(err) {
260			return fmt.Errorf("local path does not exist: %s", absPath)
261		}
262	
263		// Load package.yaml when present so local installs honor the manifest
264		// contract. If package.yaml is absent, use the plugin manifest rather than
265		// assuming a repository layout from the package name.
266		reg := registry.BuiltinRegistry()
267		fallbackPkg, _ := reg.Find(name)
268	
269		pkg, manifestMissing, manifestIssues, manifestErr := registry.LoadPackageManifestWithFallback(absPath, fallbackPkg)
270		if manifestMissing {
271			pluginPkg, ok, pluginErr := loadLocalPluginManifestPackage(absPath, name)
272			if pluginErr != nil {
273				return pluginErr
274			}
275			if ok {
276				pkg = pluginPkg
277			} else {
278				pkg = &registry.Package{
279					Name:        name,
280					Version:     "local",
281					Description: "local plugin package",
282					Type:        registry.PackageTypePlugin,
283					Source:      absPath,
284				}
285			}
286		}
287		if manifestErr == nil {
288			if strings.TrimSpace(pkg.Name) != "" && pkg.Name != name {
289				return fmt.Errorf("local package name %q does not match package.yaml name %q", name, pkg.Name)
290			}
291		} else {
292			if os.IsNotExist(manifestErr) && manifestMissing {
293				// Already handled through package.yaml absence fallback above.
294			} else if len(manifestIssues) > 0 {
295				return fmt.Errorf("validating package manifest: %w", manifestErr)
296			} else {
297				return fmt.Errorf("loading package manifest: %w", manifestErr)
298			}
299		}
300	
301		if pkg == nil {
302			pkg = &registry.Package{
303				Name:        name,
304				Version:     "local",
305				Description: "local plugin package",
306				Type:        registry.PackageTypePlugin,
307				Source:      absPath,
308			}
309		}
310	
311		if pkg.Install.Root == nil {
312			pkg.Install.Root = &registry.InstallMapping{
313				Source: ".",
314				Target: fmt.Sprintf(".ddx/plugins/%s", pkg.Name),
315			}
316		}
317	
318		if strings.HasPrefix(pkg.Install.Root.Target, "~") {
319			return fmt.Errorf("FEAT-015: Root.Target must be project-relative; got %s in package %s; update the manifest to use a relative path", pkg.Install.Root.Target, pkg.Name)
320		}
321	
322		projectRoot := f.WorkingDir
323		if projectRoot == "" {
324			projectRoot, _ = os.Getwd()
325		}
326		var oldFiles []string
327		if state, err := registry.LoadState(); err == nil {
328			if old := state.FindInstalled(pkg.Name); old != nil {
329				oldFiles = append([]string{}, old.Files...)
330				_, _ = markLocalInstallOverlay(projectRoot, pkg.Name, oldFiles)
331			}
332		}
333	
334		if issues := filterLocalInstallValidationIssues(absPath, registry.ValidatePackageStructure(absPath, pkg)); len(issues) > 0 {
335			return fmt.Errorf("validating package structure: %s", registry.JoinValidationIssues(issues))
336		}
337	
338		pluginDir := pkg.Install.Root.Target
339	
340		if err := prepareSymlinkTarget(pluginDir, force); err != nil {
341			return err
342		}
343	
344		if err := os.MkdirAll(filepath.Dir(pluginDir), 0755); err != nil {
345			return fmt.Errorf("creating plugins dir: %w", err)
346		}
347	
348		if err := os.Symlink(absPath, pluginDir); err != nil {
349			return fmt.Errorf("linking plugin into %s: %w", pluginDir, err)
350		}
351	
352		fmt.Fprintf(out, "Linked %s -> %s\n", pluginDir, absPath)
353	
354		entry := registry.InstalledEntry{
355			Name:    pkg.Name,
356			Version: pkg.Version,
357			Type:    pkg.Type,
358			Source:  absPath,
359		}
360		entry.Files = append(entry.Files, pluginDir)
361	
362		// Install local skills as symlinks into each supported harness surface.
363		if len(pkg.Install.Skills) > 0 {
364			absProject := f.WorkingDir
365			if absProject == "" {
366				absProject, _ = os.Getwd()
367			}
368			if !filepath.IsAbs(absProject) {
369				absProject, _ = filepath.Abs(absProject)
370			}
371			writtenSkills, err := installLocalSkillSymlinks(absPath, absProject, pkg.Install.Skills, force)
372			if err != nil {
373				return fmt.Errorf("installing skills: %w", err)
374			}
375			entry.Files = append(entry.Files, writtenSkills...)
376		}
377	
378		// Copy CLI script if defined (skip if target is a developer symlink).
379		if pkg.Install.Scripts != nil {
380			dst := registry.ExpandHome(pkg.Install.Scripts.Target)
381			if li, lErr := os.Lstat(dst); lErr == nil && li.Mode()&os.ModeSymlink != 0 {
382				target, _ := os.Readlink(dst)
383				fmt.Fprintf(out, "notice: %s is a symlink → %s (developer mode, skipping copy)\n", dst, target)
384				entry.Files = append(entry.Files, dst)
385			} else {
386				copied, err := registry.CopyScriptFromRoot(pluginDir, pkg.Install.Scripts)
387				if err != nil {
388					fmt.Fprintf(out, "Warning: script copy error: %v\n", err)
389				} else {
390					entry.Files = append(entry.Files, copied)
391				}
392			}
393		}
394	
395		// Set execute bits on installed plugin files.
396		for _, rel := range pkg.Install.Executable {
397			p := filepath.Join(pluginDir, filepath.FromSlash(rel))
398			if info, err := os.Stat(p); err == nil && !info.IsDir() {
399				_ = os.Chmod(p, info.Mode()|0111)
400			}
401		}
402	
403		entry.InstalledAt = time.Now()
404	
405		removed := removeStaleFilesFromInstall(oldFiles, entry.Files)
406		if removed > 0 {
407			fmt.Fprintf(out, "Removed %d stale file(s) from previous install\n", removed)
408		}
409	
410		if hidden, err := markLocalInstallOverlay(projectRoot, entry.Name, entry.Files); err != nil {
411			fmt.Fprintf(out, "Warning: local install is active but git overlay hiding failed: %v\n", err)
412		} else if hidden > 0 {
413			fmt.Fprintf(out, "Marked %d tracked local overlay file(s) skip-worktree\n", hidden)
414		}
415	
416		fmt.Fprintf(out, "Installed %s from local path %s — %d file(s); recorded plugin pin unchanged\n", entry.Name, absPath, len(entry.Files))
417		return nil
418	}
