1055		asJSON, _ := cmd.Flags().GetBool("json")
1056	
1057		state, err := registry.LoadState()
1058		if err != nil {
1059			return fmt.Errorf("reading installed state: %w", err)
1060		}
1061		if len(state.Installed) == 0 {
1062			fmt.Fprintln(out, "No packages installed.")
1063			return nil
1064		}
1065	
1066		reg := registry.BuiltinRegistry()
1067	
1068		type outdatedEntry struct {
