18	// InstallPackage downloads the source release tarball and copies declared install mappings
19	// into projectRoot. It records installed files (project-relative when possible) in the
20	// returned InstalledEntry.
21	//
22	// Compatibility shim: this is the historical entrypoint that downloads from a
23	// remote tarball. New callers should pick the explicit From* variant that
24	// matches their source (Remote/Dir/FS).
25	func InstallPackage(pkg *Package, projectRoot string) (InstalledEntry, error) {
26		return InstallPackageFromRemote(pkg, projectRoot)
27	}
28	
29	// InstallPackageFromRemote downloads the source release tarball and installs
30	// the package via the shared core install implementation.
31	func InstallPackageFromRemote(pkg *Package, projectRoot string) (InstalledEntry, error) {
32		entry := InstalledEntry{
33			Name:        pkg.Name,
34			Version:     pkg.Version,
35			Type:        pkg.Type,
36			Source:      pkg.Source,
37			InstalledAt: time.Now(),
38		}
39	
40		// FEAT-015 early validation: if the package argument already declares a
41		// home-rooted Root.Target, reject it before doing any I/O. The post-
42		// manifest check below covers manifest-supplied targets after download.
43		if pkg.Install.Root != nil && strings.HasPrefix(pkg.Install.Root.Target, "~") {
44			return entry, fmt.Errorf("FEAT-015: Root.Target must be project-relative; got %s in package %s; update the manifest to use a relative path", pkg.Install.Root.Target, pkg.Name)
45		}
46	
47		tmpDir, err := os.MkdirTemp("", "ddx-install-"+pkg.Name+"-*")
48		if err != nil {
49			return entry, fmt.Errorf("creating temp dir: %w", err)
50		}
51		defer func() { _ = os.RemoveAll(tmpDir) }()
52	
53		tarballURL := githubTarballURL(pkg.Source, pkg.Version)
54		extractedDir, err := downloadAndExtract(tarballURL, tmpDir)
55		if err != nil {
56			return entry, fmt.Errorf("downloading %s: %w", tarballURL, err)
57		}
58	
59		return installFromExtractedDir(pkg, extractedDir, projectRoot, entry)
60	}
61	
62	// InstallPackageFromFS installs the package from an in-memory or embedded
63	// filesystem (e.g. //go:embed) rooted at the package directory. The FS is
64	// materialized into a temporary directory and passed through the shared core
65	// install implementation. Network is not used.
66	func InstallPackageFromFS(pkg *Package, src iofs.FS, projectRoot string) (InstalledEntry, error) {
67		entry := InstalledEntry{
68			Name:        pkg.Name,
69			Version:     pkg.Version,
70			Type:        pkg.Type,
71			Source:      pkg.Source,
72			InstalledAt: time.Now(),
73		}
74	
75		if src == nil {
76			return entry, fmt.Errorf("InstallPackageFromFS: source fs is nil")
77		}
78	
79		if pkg.Install.Root != nil && strings.HasPrefix(pkg.Install.Root.Target, "~") {
80			return entry, fmt.Errorf("FEAT-015: Root.Target must be project-relative; got %s in package %s; update the manifest to use a relative path", pkg.Install.Root.Target, pkg.Name)
81		}
82	
83		tmpDir, err := os.MkdirTemp("", "ddx-install-fs-"+pkg.Name+"-*")
84		if err != nil {
85			return entry, fmt.Errorf("creating temp dir: %w", err)
86		}
87		defer func() { _ = os.RemoveAll(tmpDir) }()
88	
89		if err := materializeFS(src, tmpDir); err != nil {
90			return entry, fmt.Errorf("materializing embedded package: %w", err)
91		}
92	
93		return installFromExtractedDir(pkg, tmpDir, projectRoot, entry)
94	}
95	
96	// installFromExtractedDir is the shared core install routine used by the
97	// Remote, Dir, and FS entrypoints. It assumes the package contents are
98	// already present on disk at sourceDir.
99	func installFromExtractedDir(pkg *Package, sourceDir, projectRoot string, entry InstalledEntry) (InstalledEntry, error) {
100		// Switch into projectRoot so relative install targets resolve against the
101		// project, not the caller's cwd. This keeps copyMapping, ExpandHome, and
102		// the recorded entry.Files paths project-relative.
103		if projectRoot != "" {
104			absProject, absErr := filepath.Abs(projectRoot)
105			if absErr == nil {
106				if origDir, gwdErr := os.Getwd(); gwdErr == nil && origDir != absProject {
107					if err := os.Chdir(absProject); err == nil {
108						defer func() { _ = os.Chdir(origDir) }()
109					}
110				}
111			}
112		}
113	
114		if manifestPkg, manifestMissing, manifestIssues, manifestErr := LoadPackageManifestWithFallback(sourceDir, pkg); manifestErr == nil || (os.IsNotExist(manifestErr) && manifestMissing) {
115			if manifestPkg != nil {
116				pkg = manifestPkg
117			}
118		} else {
119			if len(manifestIssues) > 0 {
120				return entry, fmt.Errorf("validating package manifest: %s", JoinValidationIssues(manifestIssues))
121			}
122			return entry, fmt.Errorf("loading package manifest: %w", manifestErr)
123		}
124	
125		if pkg.Install.Root == nil {
126			pkg.Install.Root = &InstallMapping{
127				Source: ".",
128				Target: defaultPackageRootTarget(pkg.Name),
129			}
130		}
131	
132		// FEAT-015: plugin install targets must be project-relative. Manifests
133		// that try to write into the user's home are rejected so plugins can't
134		// pollute global state.
135		if strings.HasPrefix(pkg.Install.Root.Target, "~") {
136			return entry, fmt.Errorf("FEAT-015: Root.Target must be project-relative; got %s in package %s; update the manifest to use a relative path", pkg.Install.Root.Target, pkg.Name)
137		}
138	
139		if issues := ValidatePackageStructure(sourceDir, pkg); len(issues) > 0 {
140			return entry, fmt.Errorf("validating package structure: %s", JoinValidationIssues(issues))
141		}
142	
143		// Process Root mapping — copy the plugin tree into the project-local
144		// install location (e.g. .ddx/plugins/<name>/).
145		var installedRoot string
146		files, err := copyMapping(sourceDir, pkg.Install.Root)
147		if err != nil {
148			return entry, fmt.Errorf("installing plugin root: %w", err)
149		}
150		entry.Files = append(entry.Files, files...)
151		installedRoot = ExpandHome(pkg.Install.Root.Target)
152	
153		// Ensure declared executables have the execute bit set.
154		for _, rel := range pkg.Install.Executable {
155			p := filepath.Join(installedRoot, filepath.FromSlash(rel))
156			if info, err := os.Stat(p); err == nil && !info.IsDir() {
157				_ = os.Chmod(p, info.Mode()|0111)
158			}
159		}
160	
161		// Process Skills via the manifest mappings. Each mapping copies real files
162		// into its declared target. No symlinks are ever created -- this is the
163		// cross-platform invariant that FEAT-015 relies on.
164		if len(pkg.Install.Skills) > 0 {
165			written, err := installMappings(sourceDir, pkg.Install.Skills)
166			if err != nil {
167				return entry, fmt.Errorf("installing skills: %w", err)
168			}
169			entry.Files = append(entry.Files, written...)
170		}
171	
172		// Process Scripts mapping — copy the script to the target path.
173		// If the target is already a symlink, the developer is managing it
174		// themselves (e.g. symlink to their git checkout) — skip with a notice.
175		if pkg.Install.Scripts != nil {
176			dst := ExpandHome(pkg.Install.Scripts.Target)
177			if li, err := os.Lstat(dst); err == nil && li.Mode()&os.ModeSymlink != 0 {
178				target, _ := os.Readlink(dst)
179				fmt.Fprintf(os.Stderr, "notice: %s is a symlink → %s (developer mode, skipping copy)\n", dst, target)
180				entry.Files = append(entry.Files, dst)
181			} else {
182				srcDir := sourceDir
183				if installedRoot != "" {
184					srcDir = installedRoot
185				}
186				files, err := copyMapping(srcDir, pkg.Install.Scripts)
187				if err != nil {
188					return entry, fmt.Errorf("installing scripts: %w", err)
189				}
190				entry.Files = append(entry.Files, files...)
191	
192				// Ensure the installed script is executable.
193				if info, err := os.Stat(dst); err == nil && !info.IsDir() {
194					_ = os.Chmod(dst, info.Mode()|0111)
195				}
196			}
197		}
198	
199		// Process symlinks.
200		for _, sym := range pkg.Install.Symlinks {
201			src := ExpandHome(sym.Source)
202			dst := ExpandHome(sym.Target)
203	
204			// Create parent dir if needed.
205			if err := os.MkdirAll(filepath.Dir(dst), 0755); err != nil {
206				return entry, fmt.Errorf("creating symlink dir %s: %w", filepath.Dir(dst), err)
207			}
208	
209			// Remove existing symlink/file if present.
210			if _, err := os.Lstat(dst); err == nil {
211				if err := os.RemoveAll(dst); err != nil {
212					return entry, fmt.Errorf("removing existing %s: %w", dst, err)
213				}
214			}
215	
216			if err := os.Symlink(src, dst); err != nil {
217				return entry, fmt.Errorf("creating symlink %s -> %s: %w", dst, src, err)
218			}
219			entry.Files = append(entry.Files, dst)
220		}
221	
222		return entry, nil
223	}
224	
225	// materializeFS writes every regular file in src into destDir, preserving the
226	// relative path layout. Symlinks in the source FS (uncommon for embed.FS) are
227	// skipped to keep the cross-platform invariant FEAT-015 relies on.
228	func materializeFS(src iofs.FS, destDir string) error {
229		return iofs.WalkDir(src, ".", func(p string, d iofs.DirEntry, err error) error {
230			if err != nil {
231				return err
232			}
233			if p == "." {
234				return nil
235			}
236			target := filepath.Join(destDir, filepath.FromSlash(p))
237			if d.IsDir() {
238				return os.MkdirAll(target, 0o755)
239			}
240			if d.Type()&os.ModeSymlink != 0 {
241				return nil
242			}
243			if !d.Type().IsRegular() {
244				return nil
245			}
246			data, readErr := iofs.ReadFile(src, p)
247			if readErr != nil {
248				return readErr
249			}
250			if err := os.MkdirAll(filepath.Dir(target), 0o755); err != nil {
251				return err
252			}
253			return os.WriteFile(target, data, 0o644)
254		})
255	}
