257	// installMappings applies each mapping relative to srcDir and returns the
258	// project-relative files written by those mappings.
259	func installMappings(srcDir string, mappings []InstallMapping) ([]string, error) {
260		var written []string
261		for _, mapping := range mappings {
262			files, err := copyMapping(srcDir, &mapping)
263			if err != nil {
264				return nil, fmt.Errorf("copy %q -> %q: %w", mapping.Source, mapping.Target, err)
265			}
266			written = append(written, files...)
267		}
268		return written, nil
269	}
