422	// CopyScriptFromRoot copies a script from an installed plugin root to the
423	// target path. Exported for use by local install path.
424	func CopyScriptFromRoot(installedRoot string, mapping *InstallMapping) (string, error) {
425		files, err := copyMapping(installedRoot, mapping)
426		if err != nil {
427			return "", err
428		}
429		dst := ExpandHome(mapping.Target)
430		if info, err := os.Stat(dst); err == nil && !info.IsDir() {
431			_ = os.Chmod(dst, info.Mode()|0111)
432		}
433		if len(files) > 0 {
434			return files[0], nil
435		}
436		return dst, nil
437	}
438	
439	// copyMapping copies files from srcDir/<mapping.Source> to ExpandHome(mapping.Target).
440	// If the source is a single file and the target does not end with a path
441	// separator, the target is treated as the exact destination file path.
442	// If the source is a directory (or target ends with /), files are copied
443	// into the target directory.
444	// Returns the list of destination files written.
445	func copyMapping(srcDir string, mapping *InstallMapping) ([]string, error) {
446		src := filepath.Join(srcDir, filepath.FromSlash(mapping.Source))
447		dst := ExpandHome(mapping.Target)
448	
449		info, err := os.Stat(src)
450		if os.IsNotExist(err) {
451			// Source path doesn't exist in this repo — skip silently.
452			return nil, nil
453		}
454		if err != nil {
455			return nil, err
456		}
457	
458		var written []string
459	
460		if info.IsDir() {
461			// If dst is an existing symlink (e.g. from a prior --local install),
462			// remove it before creating the real directory.
463			if li, err := os.Lstat(dst); err == nil && li.Mode()&os.ModeSymlink != 0 {
464				if err := os.Remove(dst); err != nil {
465					return nil, fmt.Errorf("removing symlink at %s: %w", dst, err)
466				}
467			}
468	
469			// Copy directory tree into dst (create dst as a directory).
470			if err := os.MkdirAll(dst, 0755); err != nil {
471				return nil, fmt.Errorf("creating target dir %s: %w", dst, err)
472			}
473	
474			// HELIX skills use symlinks, so resolve each entry via os.Stat.
475			entries, err := os.ReadDir(src)
476			if err != nil {
477				return nil, err
478			}
479			for _, e := range entries {
480				srcPath := filepath.Join(src, e.Name())
481				dstPath := filepath.Join(dst, e.Name())
482	
483				fi, err := os.Stat(srcPath)
484				if err != nil {
485					if recovered := recoverSkillDir(srcDir, src, e.Name()); recovered != "" {
486						srcPath = recovered
487						fi, err = os.Stat(srcPath)
488					}
489					if err != nil {
490						continue // skip unrecoverable broken symlinks
491					}
492				}
493	
494				if fi.IsDir() {
495					subFiles, subErr := copyMapping(srcPath, &InstallMapping{Source: ".", Target: dstPath})
496					if subErr != nil {
497						return nil, subErr
498					}
499					written = append(written, subFiles...)
500				} else if fi.Mode().IsRegular() {
501					if err := copyFile(srcPath, dstPath); err != nil {
502						return nil, err
503					}
504					written = append(written, dstPath)
505				}
506			}
507		} else {
508			// Source is a single file. If target ends with /, copy into that
509			// directory using the source filename; otherwise treat target as
510			// the exact destination file path.
511			var dstFile string
512			if strings.HasSuffix(mapping.Target, "/") {
513				if err := os.MkdirAll(dst, 0755); err != nil {
514					return nil, fmt.Errorf("creating target dir %s: %w", dst, err)
515				}
516				dstFile = filepath.Join(dst, filepath.Base(src))
517			} else {
518				dstFile = dst
519			}
520			if err := copyFile(src, dstFile); err != nil {
521				return nil, err
522			}
523			written = append(written, dstFile)
524		}
525	
526		return written, nil
527	}
528	
529	// copyFile copies src to dst, creating parent directories as needed.
530	// Preserves the source file's permissions. If dst already exists (file,
531	// symlink, or directory), it is removed first.
532	func copyFile(src, dst string) error {
533		if err := os.MkdirAll(filepath.Dir(dst), 0755); err != nil {
534			return err
535		}
536	
537		// Remove any existing file/symlink/directory at dst.
538		if _, err := os.Lstat(dst); err == nil {
539			if err := os.RemoveAll(dst); err != nil {
540				return fmt.Errorf("removing existing %s: %w", dst, err)
541			}
542		}
543	
544		srcInfo, err := os.Stat(src)
545		if err != nil {
546			return err
547		}
548	
549		in, err := os.Open(src)
550		if err != nil {
551			return err
552		}
553		defer func() { _ = in.Close() }()
554	
555		out, err := os.OpenFile(dst, os.O_CREATE|os.O_WRONLY|os.O_TRUNC, srcInfo.Mode())
556		if err != nil {
557			return err
558		}
559		defer func() { _ = out.Close() }()
560	
561		_, err = io.Copy(out, in)
562		return err
563	}
564	
565	// downloadFile fetches url and writes it to dest.
566	func downloadFile(url, dest string) error {
567		resp, err := http.Get(url) //nolint:noctx
568		if err != nil {
569			return fmt.Errorf("fetching %s: %w", url, err)
570		}
571		defer func() { _ = resp.Body.Close() }()
572	
573		if resp.StatusCode != http.StatusOK {
574			return fmt.Errorf("fetching %s: HTTP %s", url, resp.Status)
575		}
576	
577		f, err := os.Create(dest)
578		if err != nil {
579			return err
580		}
581		defer func() { _ = f.Close() }()
582	
583		_, err = io.Copy(f, resp.Body)
584		return err
585	}
586	
587	// ExpandHome expands a leading ~ to the user's home directory.
588	func ExpandHome(path string) string {
589		if !strings.HasPrefix(path, "~") {
590			return path
591		}
592		home, err := os.UserHomeDir()
593		if err != nil {
594			return path
595		}
596		return filepath.Join(home, path[1:])
597	}
