12	
13	// InstalledEntry records an installed package.
14	type InstalledEntry struct {
15		Name        string      `yaml:"name"`
16		Version     string      `yaml:"version"`
17		Type        PackageType `yaml:"type"`
18		Source      string      `yaml:"source"`
19		InstalledAt time.Time   `yaml:"installed_at"`
20		Files       []string    `yaml:"files"`
21	}
22	
23	// InstalledState is the top-level structure of installed.yaml.
24	type InstalledState struct {
25		Installed []InstalledEntry `yaml:"installed"`
26	}
27	
28	// installedStatePath returns the path to ~/.ddx/installed.yaml.
29	func installedStatePath() (string, error) {
30		home, err := os.UserHomeDir()
31		if err != nil {
32			return "", fmt.Errorf("cannot determine home directory: %w", err)
33		}
34		return ddxroot.JoinHome(home, "installed.yaml"), nil
35	}
36	
37	// LoadState reads installed.yaml, returning an empty state if the file doesn't exist.
38	func LoadState() (*InstalledState, error) {
39		path, err := installedStatePath()
40		if err != nil {
41			return nil, err
42		}
43	
44		data, err := os.ReadFile(path)
45		if os.IsNotExist(err) {
46			return &InstalledState{}, nil
47		}
48		if err != nil {
49			return nil, fmt.Errorf("reading installed state: %w", err)
50		}
51	
52		var state InstalledState
53		if err := yaml.Unmarshal(data, &state); err != nil {
54			return nil, fmt.Errorf("parsing installed state: %w", err)
55		}
56		return &state, nil
57	}
58	
59	// SaveState writes installed.yaml.
60	func SaveState(state *InstalledState) error {
61		path, err := installedStatePath()
62		if err != nil {
63			return err
64		}
65	
66		if err := os.MkdirAll(filepath.Dir(path), 0755); err != nil {
67			return fmt.Errorf("creating ~/.ddx directory: %w", err)
68		}
69	
70		data, err := yaml.Marshal(state)
71		if err != nil {
72			return fmt.Errorf("marshaling installed state: %w", err)
73		}
74	
75		if err := os.WriteFile(path, data, 0644); err != nil {
76			return fmt.Errorf("writing installed state: %w", err)
77		}
78		return nil
79	}
80	
81	// VerifyFiles checks whether any recorded files for the entry exist on disk.
82	// Returns true if at least one file exists, false if all are missing.
83	func (e *InstalledEntry) VerifyFiles() bool {
84		if len(e.Files) == 0 {
85			return false
86		}
87		for _, f := range e.Files {
88			expanded := ExpandHome(f)
89			if _, err := os.Stat(expanded); err == nil {
90				return true
91			}
92			// Check if it's a symlink that resolves
93			if info, err := os.Lstat(expanded); err == nil && info.Mode()&os.ModeSymlink != 0 {
94				target, err := os.Readlink(expanded)
95				if err == nil {
96					if !filepath.IsAbs(target) {
97						target = filepath.Join(filepath.Dir(expanded), target)
98					}
99					if _, err := os.Stat(target); err == nil {
100						return true
101					}
102				}
103			}
104		}
105		return false
106	}
107	
108	// FindInstalled returns the entry for name, or nil if not installed.
109	func (s *InstalledState) FindInstalled(name string) *InstalledEntry {
110		for i := range s.Installed {
111			if s.Installed[i].Name == name {
112				return &s.Installed[i]
113			}
114		}
115		return nil
116	}
117	
118	// AddOrUpdate adds a new entry or replaces an existing one.
119	func (s *InstalledState) AddOrUpdate(entry InstalledEntry) {
120		for i := range s.Installed {
121			if s.Installed[i].Name == entry.Name {
122				s.Installed[i] = entry
123				return
124			}
125		}
126		s.Installed = append(s.Installed, entry)
127	}
128	
129	// Remove removes an entry by name. Returns false if not found.
130	func (s *InstalledState) Remove(name string) bool {
131		for i := range s.Installed {
132			if s.Installed[i].Name == name {
133				s.Installed = append(s.Installed[:i], s.Installed[i+1:]...)
134				return true
135			}
136		}
137		return false
138	}
