// InstallPackageFromRemoteGlobal downloads a package and installs it into
// globalPluginDir. Unlike the project-scoped installer, it does not chdir and
// requires globalPluginDir to be an absolute path. Each declared skill is
// linked (symlink, or directory copy on platforms that lack symlink support)
// into every directory listed in agentSkillDirs.
func InstallPackageFromRemoteGlobal(pkg *Package, globalPluginDir string, agentSkillDirs []string) (InstalledEntry, error) {
	entry := InstalledEntry{
		Name:        pkg.Name,
		Version:     pkg.Version,
		Type:        pkg.Type,
		Source:      pkg.Source,
		InstalledAt: time.Now(),
	}

	if pkg.Install.Root != nil && strings.HasPrefix(pkg.Install.Root.Target, "~") {
		return entry, fmt.Errorf("FEAT-015: Root.Target must be project-relative; got %s in package %s; update the manifest to use a relative path", pkg.Install.Root.Target, pkg.Name)
	}

	tmpDir, err := os.MkdirTemp("", "ddx-install-global-"+pkg.Name+"-*")
	if err != nil {
		return entry, fmt.Errorf("creating temp dir: %w", err)
	}
	defer func() { _ = os.RemoveAll(tmpDir) }()

	tarballURL := githubTarballURL(pkg.Source, pkg.Version)
	extractedDir, err := downloadAndExtract(tarballURL, tmpDir)
	if err != nil {
		return entry, fmt.Errorf("downloading %s: %w", tarballURL, err)
	}

	return installFromExtractedDirGlobal(pkg, extractedDir, globalPluginDir, agentSkillDirs, entry)
}

// InstallPackageFromFSGlobal installs a package from an in-memory FS into
// globalPluginDir, creating agent-tier skill links in agentSkillDirs.
func InstallPackageFromFSGlobal(pkg *Package, src iofs.FS, globalPluginDir string, agentSkillDirs []string) (InstalledEntry, error) {
	entry := InstalledEntry{
		Name:        pkg.Name,
		Version:     pkg.Version,
		Type:        pkg.Type,
		Source:      pkg.Source,
		InstalledAt: time.Now(),
	}

	if src == nil {
		return entry, fmt.Errorf("InstallPackageFromFSGlobal: source fs is nil")
	}

	if pkg.Install.Root != nil && strings.HasPrefix(pkg.Install.Root.Target, "~") {
		return entry, fmt.Errorf("FEAT-015: Root.Target must be project-relative; got %s in package %s; update the manifest to use a relative path", pkg.Install.Root.Target, pkg.Name)
	}

	tmpDir, err := os.MkdirTemp("", "ddx-install-fsglobal-"+pkg.Name+"-*")
	if err != nil {
		return entry, fmt.Errorf("creating temp dir: %w", err)
	}
	defer func() { _ = os.RemoveAll(tmpDir) }()

	if err := materializeFS(src, tmpDir); err != nil {
		return entry, fmt.Errorf("materializing embedded package: %w", err)
	}

	return installFromExtractedDirGlobal(pkg, tmpDir, globalPluginDir, agentSkillDirs, entry)
}

// installFromExtractedDirGlobal installs package contents from sourceDir into
// globalPluginDir using absolute paths (no os.Chdir). Skills are linked into
// each entry of agentSkillDirs rather than copied.
func installFromExtractedDirGlobal(pkg *Package, sourceDir, globalPluginDir string, agentSkillDirs []string, entry InstalledEntry) (InstalledEntry, error) {
	if manifestPkg, manifestMissing, manifestIssues, manifestErr := LoadPackageManifestWithFallback(sourceDir, pkg); manifestErr == nil || (os.IsNotExist(manifestErr) && manifestMissing) {
		if manifestPkg != nil {
			pkg = manifestPkg
		}
	} else {
		if len(manifestIssues) > 0 {
			return entry, fmt.Errorf("validating package manifest: %s", JoinValidationIssues(manifestIssues))
		}
		return entry, fmt.Errorf("loading package manifest: %w", manifestErr)
	}

	// Override Root.Target with the absolute globalPluginDir.
	if pkg.Install.Root == nil {
		pkg.Install.Root = &InstallMapping{Source: "."}
	}
	pkg.Install.Root.Target = globalPluginDir

	files, err := copyMapping(sourceDir, pkg.Install.Root)
	if err != nil {
		return entry, fmt.Errorf("installing plugin root: %w", err)
	}
	entry.Files = append(entry.Files, files...)

	for _, rel := range pkg.Install.Executable {
		p := filepath.Join(globalPluginDir, filepath.FromSlash(rel))
		if info, err := os.Stat(p); err == nil && !info.IsDir() {
			_ = os.Chmod(p, info.Mode()|0111)
		}
	}

	// Create agent-tier symlinks (or directory copies) for each skill.
	seenSkills := map[string]bool{}
	for _, skillMapping := range pkg.Install.Skills {
		srcBase := filepath.Join(sourceDir, filepath.FromSlash(strings.TrimSuffix(skillMapping.Source, "/")))
		ses, err := os.ReadDir(srcBase)
		if os.IsNotExist(err) {
			continue
		}
		if err != nil {
			return entry, err
		}
		for _, se := range ses {
			if !se.IsDir() {
				continue
			}
			skillName := se.Name()
			if seenSkills[skillName] {
				continue
			}
			seenSkills[skillName] = true
			installedSkill := filepath.Join(globalPluginDir, filepath.FromSlash(strings.TrimSuffix(skillMapping.Source, "/")), skillName)
			for _, agentDir := range agentSkillDirs {
				if err := os.MkdirAll(agentDir, 0o755); err != nil {
					return entry, fmt.Errorf("creating agent skill dir %s: %w", agentDir, err)
				}
				linkPath := filepath.Join(agentDir, skillName)
				_ = os.RemoveAll(linkPath)
				if err := os.Symlink(installedSkill, linkPath); err != nil {
					if copyErr := copyDirAll(installedSkill, linkPath); copyErr != nil {
						return entry, fmt.Errorf("creating skill link %s → %s: symlink: %v; copy: %w", linkPath, installedSkill, err, copyErr)
					}
				}
				entry.Files = append(entry.Files, linkPath)
			}
		}
	}

	return entry, nil
}

// InstallPackageFromRemoteWithPluginDir downloads a package and installs its
// root to pluginDir (an absolute path). Skills are installed relative to
// projectRoot using the manifest-declared target directories.
func InstallPackageFromRemoteWithPluginDir(pkg *Package, pluginDir, projectRoot string) (InstalledEntry, error) {
	entry := InstalledEntry{
		Name:        pkg.Name,
		Version:     pkg.Version,
		Type:        pkg.Type,
		Source:      pkg.Source,
		InstalledAt: time.Now(),
	}

	tmpDir, err := os.MkdirTemp("", "ddx-install-plugindir-"+pkg.Name+"-*")
	if err != nil {
		return entry, fmt.Errorf("creating temp dir: %w", err)
	}
	defer func() { _ = os.RemoveAll(tmpDir) }()

	tarballURL := githubTarballURL(pkg.Source, pkg.Version)
	extractedDir, err := downloadAndExtract(tarballURL, tmpDir)
	if err != nil {
		return entry, fmt.Errorf("downloading %s: %w", tarballURL, err)
	}

	return installFromExtractedDirWithPluginDir(pkg, extractedDir, pluginDir, projectRoot, entry)
}

// InstallPackageFromFSWithPluginDir installs from an in-memory FS, overriding
// Root.Target to pluginDir. Skills are still installed relative to projectRoot.
func InstallPackageFromFSWithPluginDir(pkg *Package, src iofs.FS, pluginDir, projectRoot string) (InstalledEntry, error) {
	entry := InstalledEntry{
		Name:        pkg.Name,
		Version:     pkg.Version,
		Type:        pkg.Type,
		Source:      pkg.Source,
		InstalledAt: time.Now(),
	}

	if src == nil {
		return entry, fmt.Errorf("InstallPackageFromFSWithPluginDir: source fs is nil")
	}

	tmpDir, err := os.MkdirTemp("", "ddx-install-fsplugindir-"+pkg.Name+"-*")
	if err != nil {
		return entry, fmt.Errorf("creating temp dir: %w", err)
	}
	defer func() { _ = os.RemoveAll(tmpDir) }()

	if err := materializeFS(src, tmpDir); err != nil {
		return entry, fmt.Errorf("materializing embedded package: %w", err)
	}

	return installFromExtractedDirWithPluginDir(pkg, tmpDir, pluginDir, projectRoot, entry)
}

// installFromExtractedDirWithPluginDir is like installFromExtractedDir but
// overrides Root.Target with pluginDir (must be absolute) after manifest load.
func installFromExtractedDirWithPluginDir(pkg *Package, sourceDir, pluginDir, projectRoot string, entry InstalledEntry) (InstalledEntry, error) {
	if projectRoot != "" {
		absProject, absErr := filepath.Abs(projectRoot)
		if absErr == nil {
			if origDir, gwdErr := os.Getwd(); gwdErr == nil && origDir != absProject {
				if err := os.Chdir(absProject); err == nil {
					defer func() { _ = os.Chdir(origDir) }()
				}
			}
		}
	}

	if manifestPkg, manifestMissing, manifestIssues, manifestErr := LoadPackageManifestWithFallback(sourceDir, pkg); manifestErr == nil || (os.IsNotExist(manifestErr) && manifestMissing) {
		if manifestPkg != nil {
			pkg = manifestPkg
		}
	} else {
		if len(manifestIssues) > 0 {
			return entry, fmt.Errorf("validating package manifest: %s", JoinValidationIssues(manifestIssues))
		}
		return entry, fmt.Errorf("loading package manifest: %w", manifestErr)
	}

	if pkg.Install.Root == nil {
		pkg.Install.Root = &InstallMapping{Source: "."}
	}
	pkg.Install.Root.Target = pluginDir

	files, err := copyMapping(sourceDir, pkg.Install.Root)
	if err != nil {
		return entry, fmt.Errorf("installing plugin root: %w", err)
	}
	entry.Files = append(entry.Files, files...)
	installedRoot := pluginDir

	for _, rel := range pkg.Install.Executable {
		p := filepath.Join(installedRoot, filepath.FromSlash(rel))
		if info, err := os.Stat(p); err == nil && !info.IsDir() {
			_ = os.Chmod(p, info.Mode()|0111)
		}
	}

	if len(pkg.Install.Skills) > 0 {
		written, err := installMappings(sourceDir, pkg.Install.Skills)
		if err != nil {
			return entry, fmt.Errorf("installing skills: %w", err)
		}
		entry.Files = append(entry.Files, written...)
	}

	if pkg.Install.Scripts != nil {
		dst := ExpandHome(pkg.Install.Scripts.Target)
		if li, err := os.Lstat(dst); err == nil && li.Mode()&os.ModeSymlink != 0 {
			target, _ := os.Readlink(dst)
			fmt.Fprintf(os.Stderr, "notice: %s is a symlink → %s (developer mode, skipping copy)\n", dst, target)
			entry.Files = append(entry.Files, dst)
		} else {
			srcDir := sourceDir
			if installedRoot != "" {
				srcDir = installedRoot
			}
			files, err := copyMapping(srcDir, pkg.Install.Scripts)
			if err != nil {
				return entry, fmt.Errorf("installing scripts: %w", err)
			}
			entry.Files = append(entry.Files, files...)
			if info, err := os.Stat(dst); err == nil && !info.IsDir() {
				_ = os.Chmod(dst, info.Mode()|0111)
			}
		}
	}

	for _, sym := range pkg.Install.Symlinks {
		src := ExpandHome(sym.Source)
		dst := ExpandHome(sym.Target)
		if err := os.MkdirAll(filepath.Dir(dst), 0755); err != nil {
			return entry, fmt.Errorf("creating symlink dir %s: %w", filepath.Dir(dst), err)
		}
		if _, err := os.Lstat(dst); err == nil {
			if err := os.RemoveAll(dst); err != nil {
				return entry, fmt.Errorf("removing existing %s: %w", dst, err)
			}
		}
		if err := os.Symlink(src, dst); err != nil {
			return entry, fmt.Errorf("creating symlink %s -> %s: %w", dst, src, err)
		}
		entry.Files = append(entry.Files, dst)
	}

	return entry, nil
}

// copyDirAll recursively copies src directory to dst. Used as a fallback when
// os.Symlink is unavailable (e.g., certain Windows configurations).
func copyDirAll(src, dst string) error {
	return filepath.Walk(src, func(path string, info os.FileInfo, err error) error {
		if err != nil {
			return err
		}
		rel, err := filepath.Rel(src, path)
		if err != nil {
			return err
		}
		target := filepath.Join(dst, rel)
		if info.IsDir() {
			return os.MkdirAll(target, info.Mode())
		}
		if !info.Mode().IsRegular() {
			return nil
		}
		return copyFile(path, target)
	})
}

