// isInTreeMode reports whether the given working directory uses the in-tree
// (.ddx/ subdirectory) layout rather than the XDG convention layout.
func isInTreeMode(workingDir string) bool {
	info, err := os.Stat(filepath.Join(workingDir, ".ddx"))
	return err == nil && info.IsDir()
}

