// runInstallGlobal installs pkg into the global DDx plugin tree.
func (f *CommandFactory) runInstallGlobal(pkg *registry.Package, force bool, out io.Writer) error {
	globalPluginDir := filepath.Join(ddxroot.GlobalDir(), "plugins", pkg.Name)

	state, _ := registry.LoadGlobalState()
	if state == nil {
		state = &registry.InstalledState{}
	}

	if old := state.FindInstalled(pkg.Name); old != nil {
		if old.Version == pkg.Version && !force {
			fmt.Fprintf(out, "%s %s is already installed globally\n", pkg.Name, pkg.Version)
			return nil
		}
	}

	homeDir, err := os.UserHomeDir()
	if err != nil {
		return fmt.Errorf("resolving home dir: %w", err)
	}
	agentSkillDirs := []string{
		filepath.Join(homeDir, ".agents", "skills"),
		filepath.Join(homeDir, ".claude", "skills"),
	}

	fmt.Fprintf(out, "Installing %s %s globally...\n", pkg.Name, pkg.Version)

	entry, err := registry.InstallPackageFromRemoteGlobal(pkg, globalPluginDir, agentSkillDirs)
	if err != nil {
		return fmt.Errorf("global install: %w", err)
	}

	state.AddOrUpdate(entry)
	if err := registry.SaveGlobalState(state); err != nil {
		return fmt.Errorf("saving global state: %w", err)
	}

	fmt.Fprintf(out, "Installed %s %s globally (%d file(s))\n", pkg.Name, pkg.Version, len(entry.Files))
	return nil
}

