// buildLocalPluginDir creates a minimal local plugin directory suitable for
// --local installs. It contains a package.yaml with the given name and a
// skills/<skillName>/SKILL.md file.
func buildLocalPluginDir(t *testing.T, pkgName, skillName string) string {
	t.Helper()
	dir := t.TempDir()

	pkgYAML := `name: ` + pkgName + `
version: 1.0.0
description: test plugin
type: plugin
source: https://example.com/` + pkgName + `
api_version: "1"
install:
  root:
    source: .
    target: .ddx/plugins/` + pkgName + `
  skills:
    - source: skills/
      target: .agents/skills/
    - source: skills/
      target: .claude/skills/
`
	require.NoError(t, os.WriteFile(filepath.Join(dir, "package.yaml"), []byte(pkgYAML), 0o644))
	skillDir := filepath.Join(dir, "skills", skillName)
	require.NoError(t, os.MkdirAll(skillDir, 0o755))
	require.NoError(t, os.WriteFile(filepath.Join(skillDir, "SKILL.md"), []byte("# "+skillName), 0o644))
	return dir
}

// buildGlobalTestPackageTarball creates a .tar.gz payload for a package that
// has a skills/ directory with one skill entry.
func buildGlobalTestPackageTarball(t *testing.T, pkgName, skillName string) []byte {
	t.Helper()
	var buf bytes.Buffer
	gz := gzip.NewWriter(&buf)
	tw := tar.NewWriter(gz)

	topDir := pkgName + "-1.0.0"
	writeTarDirHelper(t, tw, topDir)
	pkgYAML := `name: ` + pkgName + `
version: 1.0.0
description: Test package
type: plugin
source: https://example.com/` + pkgName + `
api_version: "1"
install:
  root:
    source: .
    target: .ddx/plugins/` + pkgName + `
  skills:
    - source: skills/
      target: .agents/skills/
    - source: skills/
      target: .claude/skills/
`
	writeTarFileHelper(t, tw, filepath.Join(topDir, "package.yaml"), []byte(pkgYAML))
	writeTarDirHelper(t, tw, filepath.Join(topDir, "skills"))
	writeTarDirHelper(t, tw, filepath.Join(topDir, "skills", skillName))
	writeTarFileHelper(t, tw, filepath.Join(topDir, "skills", skillName, "SKILL.md"),
		[]byte("# "+skillName+"\n"))
	require.NoError(t, tw.Close())
	require.NoError(t, gz.Close())
	return buf.Bytes()
}

func writeTarDirHelper(t *testing.T, tw *tar.Writer, name string) {
	t.Helper()
	require.NoError(t, tw.WriteHeader(&tar.Header{
		Name:     filepath.ToSlash(name) + "/",
		Mode:     0o755,
		Typeflag: tar.TypeDir,
	}))
}

func writeTarFileHelper(t *testing.T, tw *tar.Writer, name string, body []byte) {
	t.Helper()
	require.NoError(t, tw.WriteHeader(&tar.Header{
		Name:     filepath.ToSlash(name),
		Mode:     0o644,
		Size:     int64(len(body)),
		Typeflag: tar.TypeReg,
	}))
	_, err := tw.Write(body)
	require.NoError(t, err)
}

func newGlobalPackageServer(t *testing.T, payload []byte) *httptest.Server {
	t.Helper()
	return httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		if !strings.Contains(r.URL.Path, "/archive/refs/tags/") {
			http.NotFound(w, r)
			return
		}
		w.Header().Set("Content-Type", "application/gzip")
		_, _ = w.Write(payload)
	}))
}

