func TestInstallGlobal_WritesXDGAndAgentTierLinks(t *testing.T) {
	homeDir := t.TempDir()
	t.Setenv("HOME", homeDir)
	xdgDir := t.TempDir()
	t.Setenv("XDG_DATA_HOME", xdgDir)

	te := NewTestEnvironment(t, WithGitInit(false))

	// Build a local plugin dir so we avoid any network calls.
	localDir := buildLocalPluginDir(t, "test-plugin", "my-skill")

	output, err := te.RunCommand("install", "test-plugin", "--local", localDir, "--global", "--silent")
