	require.True(t, info.Mode()&os.ModeSymlink != 0, "global plugin dir should be a symlink")

	// Agent-tier links must exist under ~/.claude/skills and ~/.agents/skills.
	for _, rel := range []string{
		filepath.Join(".claude", "skills", "my-skill"),
		filepath.Join(".agents", "skills", "my-skill"),
