		_, err := os.Stat(linkPath)
		assert.NoError(t, err, "agent-tier link should exist: %s", linkPath)
	}

	// Global state should record the entry; project state should be untouched.
	globalState, err := registry.LoadGlobalState()
	require.NoError(t, err)
	assert.NotNil(t, globalState.FindInstalled("test-plugin"), "global state should record the install")
}

