// TestUpdateGlobal_UpdatesGlobalNotProject verifies that ddx update --global
// only operates on the global plugin state and does not modify the project
// install state.
func TestUpdateGlobal_UpdatesGlobalNotProject(t *testing.T) {
	homeDir := t.TempDir()
	t.Setenv("HOME", homeDir)
	xdgDir := t.TempDir()
	t.Setenv("XDG_DATA_HOME", xdgDir)

	te := NewTestEnvironment(t, WithGitInit(false))

	// Populate a project-level installed state entry.
	projectState := &registry.InstalledState{
		Installed: []registry.InstalledEntry{
			{Name: "project-plugin", Version: "1.0.0", Type: registry.PackageTypePlugin},
		},
	}
	require.NoError(t, registry.SaveState(projectState))

	// Run ddx update --global (no global packages installed → should be a no-op).
	output, err := te.RunCommand("update", "--global")
	require.NoError(t, err, "update --global should not error when no global packages are installed; output: %s", output)
	assert.Contains(t, output, "globally", "output should mention global context")

	// Project state must be untouched.
	reloaded, err := registry.LoadState()
	require.NoError(t, err)
	assert.NotNil(t, reloaded.FindInstalled("project-plugin"), "project state must be untouched by --global update")
}

// TestUpdate_RespectsConventionVsInTreeMode verifies that ddx update (without
// --global) refreshes shipped skills regardless of whether the project uses
// in-tree (.ddx/) or convention (XDG) layout, and does not touch the global
// plugin state.
func TestUpdate_RespectsConventionVsInTreeMode(t *testing.T) {
	homeDir := t.TempDir()
	t.Setenv("HOME", homeDir)
	xdgDir := t.TempDir()
	t.Setenv("XDG_DATA_HOME", xdgDir)

	// Populate global state so we can verify it is NOT touched.
	globalState := &registry.InstalledState{
		Installed: []registry.InstalledEntry{
			{Name: "global-plugin", Version: "1.0.0", Type: registry.PackageTypePlugin},
		},
	}
	require.NoError(t, registry.SaveGlobalState(globalState))

	for _, tc := range []struct {
		name    string
		inTree  bool
	}{
		{"in-tree mode", true},
		{"convention mode", false},
	} {
		t.Run(tc.name, func(t *testing.T) {
			te := NewTestEnvironment(t, WithGitInit(false))
			if tc.inTree {
				require.NoError(t, os.MkdirAll(filepath.Join(te.Dir, ".ddx"), 0o755))
			}

			output, err := te.RunCommand("update")
			require.NoError(t, err, "ddx update should succeed in %s; output: %s", tc.name, output)

			// Must mention shipped skill refresh.
			assert.Contains(t, output, "Shipped skills refreshed",
				"ddx update should refresh shipped skills in %s", tc.name)

			// Global state must be untouched.
			reloaded, err := registry.LoadGlobalState()
			require.NoError(t, err)
			entry := reloaded.FindInstalled("global-plugin")
			require.NotNil(t, entry, "global state should not be modified by non-global update in %s", tc.name)
			assert.Equal(t, "1.0.0", entry.Version)
		})
	}
}

